import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authApi, userApi } from '../api/client';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true);

  // Ilova yuklanishida saqlangan tokenni tekshirish
  useEffect(() => {
    const token = localStorage.getItem('accessToken');
    if (token) {
      userApi.getMe()
        .then(({ data }) => setUser(data.data))
        .catch(() => localStorage.clear())
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = useCallback((authData) => {
    localStorage.setItem('accessToken',  authData.accessToken);
    localStorage.setItem('refreshToken', authData.refreshToken);
    localStorage.setItem('role',         authData.role);
    userApi.getMe().then(({ data }) => setUser(data.data));
  }, []);

  const logout = useCallback(async () => {
    try { await authApi.logout(); } catch {}
    localStorage.clear();
    setUser(null);
  }, []);

  const role = localStorage.getItem('role');

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, role,
      isAdmin:   role === 'ADMIN',
      isCourier: role === 'COURIER',
      isCustomer: role === 'CUSTOMER' || role === 'FARMER',
    }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
